const resume_id = $input.first().json.body?.resume_id;
const target_role = $input.first().json.body?.target_role || null;
const target_company = $input.first().json.body?.target_company || null;

if (!resume_id) throw new Error('Campo resume_id não encontrado no body.');

return [{ json: { resume_id, target_role, target_company } }];

const data = $input.first().json;
const meta = $('Code - Valida Body').first().json;

if (!data || !data.resume_id) {
  throw new Error(`Análise não encontrada para resume_id: ${meta.resume_id}`);
}

const redFlags = typeof data.red_flags === 'string' ? JSON.parse(data.red_flags) : data.red_flags;
const tips = typeof data.improvement_tips === 'string' ? JSON.parse(data.improvement_tips) : data.improvement_tips;

const targetContext = meta.target_role
  ? `\n\nIMPORTANT: Tailor this resume specifically for the role of '${meta.target_role}'${ meta.target_company ? ` at ${meta.target_company}` : '' }. Use keywords and skills typical for this role.`
  : '';

const prompt = `You are a world-class resume writer and career strategist. You already analyzed this resume and found these issues:

Brutal Roast: ${data.brutal_roast}
Red Flags: ${JSON.stringify(redFlags)}
Improvement Tips: ${JSON.stringify(tips)}
Current Summary: ${data.rewritten_summary}${targetContext}

Now create a COMPLETE, FULLY REWRITTEN resume based on these findings. Return ONLY a strict JSON with:
1) 'new_summary': optimized professional summary (3-4 lines)
2) 'key_skills': array of 10-15 relevant technical and soft skills
3) 'experience_bullets': array of 5-8 achievement-focused bullet points using STAR method and numbers
4) 'certifications_suggestions': array of 3 relevant certifications to pursue
5) 'ats_keywords': array of 15 keywords to add for ATS optimization
6) 'final_score_prediction': predicted employability score after applying all changes (number 0-100)
7) 'cover_letter_opening': a strong opening paragraph for a cover letter`;

return [{ json: { prompt, resume_id: data.resume_id, original_score: data.employability_score } }];

const resumeId = $('Code - Valida Body').first().json.resume_id;
const originalScore = $('Code - Monta Prompt com Contexto').first().json.original_score;
const content = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content;

let parsed;
try {
  parsed = typeof content === 'string' ? JSON.parse(content) : content;
} catch(e) {
  throw new Error('GPT-4o não retornou JSON válido: ' + content);
}

return [{
  json: {
    resume_id: resumeId,
    original_score: originalScore,
    final_score_prediction: parsed.final_score_prediction,
    score_improvement: parsed.final_score_prediction - originalScore,
    new_summary: parsed.new_summary,
    key_skills: parsed.key_skills,
    experience_bullets: parsed.experience_bullets,
    certifications_suggestions: parsed.certifications_suggestions,
    ats_keywords: parsed.ats_keywords,
    cover_letter_opening: parsed.cover_letter_opening,
    generated_at: new Date().toISOString()
  }
}];
